function resolveContentKey(locale: ContentLocale, market: ContentMarket): ContentKey {
  if (locale === "es") return "es:es";
  if (locale === "pt") return "pt:pt";
  return market === "eu" ? "en:eu" : "en:us";
}

export function getCalculatorSeoContent(
  internalSlug: string,
  locale: ContentLocale,
  market: ContentMarket
): SeoCalculatorContent | null {
  const slugContent = CONTENT[internalSlug];
  if (!slugContent) return null;
  const key = resolveContentKey(locale, market);
  return slugContent[key] ?? null;
}
